import{_ as a,o as r,c as o,ae as e}from"./chunks/framework.BeMCGcrk.js";const _=JSON.parse('{"title":"小米集团（01810.HK）行情分析 | 2026年6月16日","description":"","frontmatter":{},"headers":[],"relativePath":"blog/2026-06-16-12.md","filePath":"blog/2026-06-16-12.md"}'),d={name:"blog/2026-06-16-12.md"};function l(n,t,i,s,h,g){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="小米集团-01810-hk-行情分析-2026年6月16日" tabindex="-1">小米集团（01810.HK）行情分析 | 2026年6月16日 <a class="header-anchor" href="#小米集团-01810-hk-行情分析-2026年6月16日" aria-label="Permalink to &quot;小米集团（01810.HK）行情分析 | 2026年6月16日&quot;">​</a></h1><h2 id="今日行情快照" tabindex="-1">今日行情快照 <a class="header-anchor" href="#今日行情快照" aria-label="Permalink to &quot;今日行情快照&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数值</th></tr></thead><tbody><tr><td>现价</td><td><strong>25.920 HKD</strong></td></tr><tr><td>今日涨跌</td><td><strong>-1.29%</strong></td></tr><tr><td>开盘</td><td>26.260 HKD</td></tr><tr><td>最高</td><td>26.360 HKD</td></tr><tr><td>最低</td><td>25.660 HKD</td></tr><tr><td>成交量</td><td>4303万股的承接</td></tr><tr><td>市盈率 PE</td><td>61.45</td></tr><tr><td>52周高点</td><td>约35.5 HKD</td></tr><tr><td>距52周高点</td><td><strong>-26.70%</strong></td></tr><tr><td>年初至今</td><td><strong>-34.05%</strong></td></tr></tbody></table><h2 id="持仓状态" tabindex="-1">持仓状态 <a class="header-anchor" href="#持仓状态" aria-label="Permalink to &quot;持仓状态&quot;">​</a></h2><ul><li><strong>持仓数量</strong>：2800股</li><li><strong>成本价</strong>：33.99 CNY（约39.41 HKD，按1 HKD=0.86252 CNY换算）</li><li><strong>当前价位</strong>：25.920 HKD（约22.34 CNY）</li><li><strong>浮动亏损</strong>：约 <strong>-34.3%</strong></li><li><strong>止损参考</strong>：33.50 HKD（远高于现价，当前的参考意义有限）</li></ul><blockquote><p>注：成本价为人民币（CNY），港股现价需按实时汇率换算后与成本对比。</p></blockquote><h2 id="操作建议-观望" tabindex="-1">操作建议：<strong>观望</strong> <a class="header-anchor" href="#操作建议-观望" aria-label="Permalink to &quot;操作建议：**观望**&quot;">​</a></h2><p><strong>不加分不减分，耐心持有。</strong></p><p>理由如下：</p><h3 id="_1-跌幅已深-但未见止跌信号" tabindex="-1">1. 跌幅已深，但未见止跌信号 <a class="header-anchor" href="#_1-跌幅已深-但未见止跌信号" aria-label="Permalink to &quot;1. 跌幅已深，但未见止跌信号&quot;">​</a></h3><p>年初至今跌幅 -34.05%，现价距52周高点折让 -26.70%，技术面仍然承压：股价运行于各条均线下方，短期趋势偏弱，尚无明显企稳迹象。</p><h3 id="_2-宏观压制未解除" tabindex="-1">2. 宏观压制未解除 <a class="header-anchor" href="#_2-宏观压制未解除" aria-label="Permalink to &quot;2. 宏观压制未解除&quot;">​</a></h3><p>关税博弈持续扰动科技出口链情绪，智能手机市场竞争加剧（荣耀、传音、OV持续蚕食份额），小米汽车放量节奏存在不确定性。对产业链的担忧压制着估值。</p><h3 id="_3-止损线已无实际意义" tabindex="-1">3. 止损线已无实际意义 <a class="header-anchor" href="#_3-止损线已无实际意义" aria-label="Permalink to &quot;3. 止损线已无实际意义&quot;">​</a></h3><p>止损位设于33.50 HKD，而当前价格仅25.920 HKD——止损线在现价上方约29%处，并非下跌保护，而是上涨触发条件。持仓已浮亏34%，建议降低对技术止损的依赖，转而关注公司基本面逻辑是否还在。</p><h3 id="_4-长期逻辑未破坏" tabindex="-1">4. 长期逻辑未破坏 <a class="header-anchor" href="#_4-长期逻辑未破坏" aria-label="Permalink to &quot;4. 长期逻辑未破坏&quot;">​</a></h3><p>小米的核心逻辑是生态硬件+汽车第二曲线。当前手机业务基本盘稳定，IoT设备持续扩列，SU7汽车从交付爬坡中逐步建立品牌认知。如果认可这套长期叙事，现在的价位是值得等待的——但前提是有足够的耐心资本。</p><h3 id="_5-不加分的原因" tabindex="-1">5. 不加分的原因 <a class="header-anchor" href="#_5-不加分的原因" aria-label="Permalink to &quot;5. 不加分的原因&quot;">​</a></h3><p>不是不看好，而是时机不对。加仓应该在两种情况下考虑：</p><ul><li>市场恐慌、情绪极度悲观时（类似2025年某几个节点的超跌）</li><li>技术面出现明显底部信号（缩量十字星、放量阳线等）</li></ul><p>目前两个条件均未满足，贸然加仓只会放大亏损。</p><h2 id="后续跟踪重点" tabindex="-1">后续跟踪重点 <a class="header-anchor" href="#后续跟踪重点" aria-label="Permalink to &quot;后续跟踪重点&quot;">​</a></h2><ol><li><strong>成交量</strong>：港股低量市场下，股价易暴涨暴跌，缩量止跌才是真正企稳信号</li><li><strong>小米汽车</strong>：月度交付数据，持续超预期会修复市场信心</li><li><strong>关税动向</strong>：贸易摩擦缓和将直接利好整个科技出口链</li><li><strong>汇率</strong>：若港元汇率波动，换算后实际亏损可能扩大</li></ol><hr><p><em>免责声明：本文仅为个人投资记录与思考，不构成投资建议。股市有风险，投资需谨慎。</em></p>',25)])])}const p=a(d,[["render",l]]);export{_ as __pageData,p as default};
